import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";

function OfferLetterPreview() {
  const { applicationId } = useParams();
  const [offer, setOffer] = useState(null);
  const [application, setApplication] = useState(null);

  useEffect(() => {
    const offers = JSON.parse(localStorage.getItem("offerLetters")) || [];
    const applications = JSON.parse(localStorage.getItem("applications")) || [];

    setOffer(
      offers.find(o => String(o.applicationId) === String(applicationId))
    );

    setApplication(
      applications.find(a => String(a.id) === String(applicationId))
    );
  }, [applicationId]);

  if (!offer || !application) {
    return <p style={{ marginTop: "25px" }}>Offer Letter not found.</p>;
  }

  const candidateName =
    application.employeeName || application.employee || "Candidate";

  return (
    <div
      style={{
        marginTop: "25px",
        maxWidth: "700px",
        background: "#ffffff",
        padding: "25px",
        borderRadius: "10px",
        boxShadow: "0 6px 18px rgba(0,0,0,0.08)"
      }}
    >
      <h2>Offer Letter</h2>
      <hr />

      <p><b>Candidate Name:</b> {candidateName}</p>
      <p><b>Email:</b> {offer.email}</p>
      <p><b>Job Title:</b> {offer.jobTitle}</p>

      <hr />

      <p><b>Annual Salary:</b> ₹{offer.salary}</p>
      <p><b>Work Location:</b> {offer.location}</p>
      <p><b>Joining Date:</b> {offer.joiningDate}</p>
      <p><b>Offer Date:</b> {offer.offerDate}</p>

      {offer.notes && (
        <>
          <hr />
          <p><b>Notes:</b></p>
          <p>{offer.notes}</p>
        </>
      )}

      <hr />
      <p style={{ marginTop: "30px" }}>
        <b>Authorized Signatory</b><br />
        HR Department
      </p>
    </div>
  );
}

export default OfferLetterPreview;
